// CyberPunkMetalHead/Binance-volatility-trading-bot mantДұДҹДұ
// 5m ve 15m'de en fazla hareket eden, hacimli, aktif coinleri seГ§
const volatilityStore = { coins:[], lastUpdate:0 };

// в”Җв”Җ R25: TR SAAT FORMATI (Europe/Istanbul = UTC+3) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function trTime(ts = Date.now()) {
  try {
    return new Intl.DateTimeFormat('tr-TR', {
      timeZone: 'Europe/Istanbul',
      day: '2-digit', month: '2-digit', year: 'numeric',
      hour: '2-digit', minute: '2-digit', second: '2-digit',
      hour12: false
    }).format(new Date(ts));
  } catch(_) {
    return new Date(ts + 3*60*60*1000).toISOString().replace('T',' ').substring(0,19) + ' TR';
  }
}

