let   tgLastSent = 0;
let   tgQueue = Promise.resolve();
const TG_MIN_GAP = 1200; // art arda mesajДұ dГјЕҹГјrme; kДұsa gecikmeyle sДұraya al
const r185OrderOpenSent = new Set();

function tgEsc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
function tgNum(v, d=2) {
  const n = Number(v);
  return Number.isFinite(n) ? n.toFixed(d) : '-';
}
function tgEnabled() { return !!(TG_TOKEN && TG_CHAT_ID); }

async function r184DirectTelegramText(text, silent=false) {
  if (!tgEnabled()) return {ok:false, skipped:true, reason:'telegram_env_missing', error:'telegram_env_missing'};
  try {
    const res = await fetch(`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        chat_id: TG_CHAT_ID,
        text: String(text).slice(0,3900),
        disable_notification: !!silent,
      }),
      signal: AbortSignal.timeout(10000),
    });
    const data = await res.json().catch(()=>({}));
    if (!res.ok || data.ok === false) {
      const err = data.description || `HTTP_${res.status}`;
      try { console.log(`[telegram sessiz baЕҹarДұsДұz] ${err}`); } catch(_) {} // R318B: kritik kutuya yazma, sessiz
      return {ok:false, error:err, status:res.status, data};
    }
    return {ok:true, messageId:data?.result?.message_id || null};
  } catch(e) {
    const err = String(e?.message || e);
    try { console.log(`[telegram sessiz baЕҹarДұsДұz] ${err}`); } catch(_) {} // R318B: kritik kutuya yazma, sessiz
    return {ok:false, error:err};
  }
}

async function tgSendNow(text, silent=false) {
  if (!tgEnabled()) return {ok:false, skipped:true, reason:'telegram_env_missing'};
  const wait = Math.max(0, TG_MIN_GAP - (Date.now() - tgLastSent));
  if (wait > 0) await new Promise(r => setTimeout(r, wait));
  tgLastSent = Date.now();
  try {
    const res = await fetch(`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({
        chat_id: TG_CHAT_ID,
        text: String(text).slice(0, 3900),
        parse_mode: 'HTML',
        disable_notification: !!silent,
      }),
      signal: AbortSignal.timeout(8000),
    });
    const data = await res.json().catch(()=>({}));
    if (!res.ok || data.ok === false) {
      const err = data.description || `HTTP_${res.status}`;
      // R171: HTML parse vb. yГјzГјnden trade kartДұ dГјЕҹmesin; dГјz metin fallback dene.
      try {
        const plain = String(text)
          .replace(/<[^>]+>/g, '')
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>');
        const r2 = await fetch(`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, {
          method:'POST',
          headers:{'Content-Type':'application/json'},
          body: JSON.stringify({chat_id:TG_CHAT_ID, text:plain.slice(0,3900), disable_notification:!!silent}),
          signal: AbortSignal.timeout(8000),
        });
        const d2 = await r2.json().catch(()=>({}));
        if (r2.ok && d2.ok !== false) return {ok:true, fallback:'plain_text', originalError:err};
      } catch(_fallbackErr) {}
      try { console.log('[telegram sessiz baЕҹarДұsДұz] TELEGRAM_SEND_FAIL:', err); } catch(_) {}
      console.log('вҡ пёҸ Telegram gГ¶nderim hatasДұ:', err);
      return {ok:false, error:err};
    }
    return {ok:true};
  } catch(e) {
    const err = String(e?.message || e).slice(0,160);
    try { console.log('[telegram sessiz baЕҹarДұsДұz] TELEGRAM_SEND_FAIL:', err); } catch(_) {}
    console.log('вҡ пёҸ Telegram gГ¶nderim exception:', err);
    return {ok:false, error:err};
  }
}

function tgSend(text, silent=false) {
  // Eski kod 3sn iГ§inde gelen mesajДұ direkt Г§Г¶pe atДұyordu. R168b: kuyruk var, mesaj kaybolmaz.
  tgQueue = tgQueue.then(() => tgSendNow(text, silent)).catch(() => {});
  return tgQueue;
}

function tgFmtUsd(v, d=2) {
  const n = Number(v);
  if (!Number.isFinite(n)) return '-';
  return `${n >= 0 ? '+' : ''}${n.toFixed(d)}$`;
}
function tgFmtPct(v, d=2) {
  const n = Number(v);
  if (!Number.isFinite(n)) return '-';
  return `${n >= 0 ? '+' : ''}${n.toFixed(d)}%`;
}
function tgPrice(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return '-';
  if (n < 0.001) return n.toFixed(8);
  if (n < 0.1) return n.toFixed(6);
  if (n < 10) return n.toFixed(5);
  return n.toFixed(4);
}
function tgMovePct(entry, price, side='LONG') {
  const e = Number(entry), p = Number(price);
  if (!(e > 0 && p > 0)) return null;
  const raw = (p - e) / e * 100 * (normalizeSide(side) === 'SHORT' ? -1 : 1);
  return raw;
}
function tgRoiFromPrice(entry, price, side, lev) {
  const m = tgMovePct(entry, price, side);
  const l = Number(lev || 1) || 1;
  return Number.isFinite(m) ? m * l : null;
}
function tgTradeOpen(symbol, side, score, edge, margin, leverage, reason, extra={}) {
  const icon = side === 'LONG' ? 'рҹҹў' : 'рҹ”ҙ';
  const dirTR = side === 'LONG' ? 'LONG вҶ‘' : 'SHORT вҶ“';
  const lev = Number(leverage || extra.leverage || 1) || 1;
  const mar = Number(margin || extra.margin || 0) || 0;
  const qty = Number(extra.quantity || extra.qty || 0);
  const pos = mar * lev;
  const entry = Number(extra.entryPrice || extra.entry || 0);
  const sl = Number(extra.slPrice || extra.stopPrice || extra.currentSL || 0);
  const tp = Number(extra.tpPrice || extra.targetPrice || extra.targetTP || 0);
  const slMove = tgMovePct(entry, sl, side);
  const tpMove = tgMovePct(entry, tp, side);
  const slRoi = tgRoiFromPrice(entry, sl, side, lev);
  const tpRoi = tgRoiFromPrice(entry, tp, side, lev);
  const rr = (Number.isFinite(slMove) && Number.isFinite(tpMove) && Math.abs(slMove) > 0)
    ? Math.abs(tpMove / slMove) : null;
  const lines = [
    `${icon} <b>Д°ЕһLEM AГҮILDI</b> вҖ” <b>${tgEsc(symbol)}</b> ${dirTR}`,
    `в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ`,
    `рҹ’° Marjin: <b>${tgNum(mar,2)} USDT</b> | Pozisyon: <b>${tgNum(pos,2)} USDT</b> | Lev: <b>${tgEsc(lev)}x</b>`,
  ];
  if (qty) lines.push(`рҹ“Ұ Miktar: <b>${tgNum(qty,6)}</b>`);
  if (entry) lines.push(`рҹҺҜ Entry: <b>$${tgPrice(entry)}</b>`);
  if (sl || tp) lines.push(`рҹӣЎ SL: <b>$${tgPrice(sl)}</b> | рҹҺҜ TP: <b>$${tgPrice(tp)}</b>`);
  if (Number.isFinite(slRoi) || Number.isFinite(tpRoi)) {
    lines.push(`рҹ“җ Risk/Г–dГјl: SL <b>${tgFmtPct(slRoi,1)} ROI</b> | TP <b>${tgFmtPct(tpRoi,1)} ROI</b>${Number.isFinite(rr) ? ` | RR <b>${tgNum(rr,2)}</b>` : ''}`);
  } else if (extra.slPct || extra.tpPct) {
    lines.push(`рҹ“җ SL: <b>%${tgEsc(extra.slPct)}</b> | TP: <b>%${tgEsc(extra.tpPct)}</b> (kaldДұraГ§sДұz)`);
  }
  lines.push(`рҹ“Ҡ Skor: <b>${tgEsc(score)}</b> | Edge: <b>${tgEsc(edge)}/100</b>${extra.tier ? ` | Tier: <b>${tgEsc(extra.tier)}</b>` : ''}`);
  if (extra.mode || extra.brainMode) lines.push(`рҹ§  Mod: <b>${tgEsc(extra.mode || extra.brainMode)}</b>`);
  if (reason) lines.push(`рҹ“қ Sebep: ${tgEsc(String(reason).slice(0,220))}`);
  if (extra.sltpVerified !== undefined) lines.push(`вң… SL/TP Binance: <b>${extra.sltpVerified ? 'doДҹrulandДұ' : 'kontrol et'}</b>`);
  lines.push(`в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ`);
  lines.push(...tgPerfSummaryLines());
  lines.push(`рҹҸ· Build: ${tgEsc(LAZARUS_BUILD)}`);
  lines.push(`вҸ° ${new Date().toLocaleString('tr-TR')}`);
  return tgSend(lines.join('\n'), false);
}

function tgTradeClose(symbol, side, pnl, roi, closeReason, extra={}) {
  const pn = Number(pnl);
  const ro = Number(roi);
  const win = Number.isFinite(pn) ? pn >= 0 : (Number.isFinite(ro) ? ro >= 0 : false);
  const icon = win ? 'вң…' : 'вқҢ';
  const emojiPnl = win ? 'рҹӨ‘' : 'рҹҳ¬';
  const dirTR = side === 'LONG' ? 'LONG вҶ‘' : (side === 'SHORT' ? 'SHORT вҶ“' : tgEsc(side||'?'));
  const entry = Number(extra.entryPrice || extra.entry || 0);
  const close = Number(extra.closePrice || extra.exitPrice || 0);
  const sl = Number(extra.sl || extra.slPrice || extra.currentSL || 0);
  const tp = Number(extra.tp || extra.tpPrice || extra.targetTP || 0);
  const qty = Number(extra.quantity || extra.qty || 0);
  const lev = Number(extra.leverage || 0);
  const margin = Number(extra.marginUSDT || extra.margin || 0);
  const rawMove = tgMovePct(entry, close, side);
  const lines = [
    `${icon} <b>Д°ЕһLEM KAPANDI</b> вҖ” <b>${tgEsc(symbol)}</b> ${dirTR}`,
    `в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ`,
    `${emojiPnl} PnL: <b>${Number.isFinite(pn) ? tgFmtUsd(pn,2) : 'bilinmiyor'}</b> | ROI: <b>${Number.isFinite(ro) ? tgFmtPct(ro,1) : 'bilinmiyor'}</b>`,
  ];
  if (entry || close) lines.push(`рҹ’№ Entry: <b>$${tgPrice(entry)}</b> вҶ’ ГҮДұkДұЕҹ: <b>$${tgPrice(close)}</b>${Number.isFinite(rawMove) ? ` | Coin hareketi: <b>${tgFmtPct(rawMove,2)}</b>` : ''}`);
  if (sl || tp) lines.push(`рҹӣЎ AГ§ДұlДұЕҹ SL: <b>$${tgPrice(sl)}</b> | TP: <b>$${tgPrice(tp)}</b>`);
  if (lev || margin || qty) lines.push(`рҹ’ј Marjin: <b>${margin ? tgNum(margin,2)+' USDT' : '-'}</b> | Lev: <b>${lev || '-'}x</b> | Miktar: <b>${qty ? tgNum(qty,6) : '-'}</b>`);
  if (extra.duration) lines.push(`вҸұ SГјre: <b>${tgEsc(extra.duration)}</b>`);
  if (extra.peakRoi !== undefined || extra.peakPnl !== undefined) lines.push(`рҹ“Ҳ Zirve ROI: <b>${extra.peakRoi!==undefined ? tgFmtPct(extra.peakRoi,1) : '-'}</b> | Zirve PnL: <b>${extra.peakPnl!==undefined ? tgFmtUsd(extra.peakPnl,2) : '-'}</b>`);
  if (closeReason) lines.push(`рҹ“Ӣ KapanДұЕҹ: ${tgEsc(String(closeReason).slice(0,160))}`);
  if (extra.resultNote) lines.push(`рҹ§ҫ SonuГ§: ${tgEsc(String(extra.resultNote).slice(0,180))}`);
  lines.push(`в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ`);
  lines.push(...tgPerfSummaryLines());
  lines.push(`рҹҸ· Build: ${tgEsc(LAZARUS_BUILD)}`);
  lines.push(`вҸ° ${new Date().toLocaleString('tr-TR')}`);
  return tgSend(lines.join('\n'), win);
}

