        // Sadece gerГ§ekten Г¶lГј hacim (<0.20x) otomatik kГ¶prГјyГј kilitler; 0.20-0.70 arasДұ ceza/uyarДұ olarak kalДұr.
        const rvolVeryLow = !!(rvol1h && Number(rvol1h.rvol || 0) < 0.20);
        const _slPctEval = parseFloat(autoConfig?.slPct || 2);
