// в”Җв”Җ R366: VOLATД°LД°TE SEBEP WORKER'I в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Tarama 7.5dk'da bir; arada TOP coinlerin 1dk hareketini saf-kod ile takip eder ve
// "Еҹu sebeple yГјkseliyor / bu sebeple dГјЕҹГјyor" bilgisi Гјretir. AI Г§aДҹrДұsДұ YOK вҖ” sadece Binance public.
// Bu bilgi autoScanState.volatiliteSebep'e yazДұlДұr; AI bir sonraki taramada tam bilgilendirilmiЕҹ olur.
let __r366VolSebep = {}; // { COIN: { ts, yon, sebepler[], hiz, ivme } }
async function r366VolatiliteWorker() {
  try {
    if (!autoConfig?.enabled) return;
    const coins = await r343RadarUniverse();
    for (const base of coins) {
      const full = base.endsWith('USDT') ? base : base + 'USDT';
      try {
        // 1dk mum (son 20) + funding + OI + taker вҖ” hepsi bedava public
        const [kl, agg] = await Promise.all([
          bPub('/fapi/v1/klines', `symbol=${full}&interval=1m&limit=20`).catch(()=>null),
          bPub('/futures/data/takerlongshortRatio', `symbol=${full}&period=5m&limit=3`).catch(()=>null)
        ]);
        if (!Array.isArray(kl) || kl.length < 10) continue;
        const b = kl.map(c => ({ o:+c[1], h:+c[2], l:+c[3], c:+c[4], v:+c[5], tb:+c[9] }));
        const n = b.length;
        const last = b[n-1], prev = b[n-2];
        // ATR(10) 1m
        let atr=0,cnt=0; for(let i=n-10;i<n;i++){if(i<1)continue; atr+=Math.max(b[i].h-b[i].l,Math.abs(b[i].h-b[i-1].c),Math.abs(b[i].l-b[i-1].c));cnt++;}
        atr=cnt?atr/cnt:0;
        // Son 5 mum yГ¶n ve hДұz
        const son5 = b.slice(-5);
        const net5 = last.c - son5[0].o;
        const yon = net5 > atr*0.5 ? 'YГңKSELД°YOR' : net5 < -atr*0.5 ? 'DГңЕһГңYOR' : 'YATAY';
        if (yon === 'YATAY') { delete __r366VolSebep[base]; continue; }
        const hiz = atr>0 ? +(Math.abs(net5)/atr).toFixed(1) : 0; // kaГ§ ATR'lik 5dk hareket
        // ivme: son 3 mum gГ¶vde ort vs Г¶nceki
        const g=(a,z)=>{let s=0;for(let i=a;i<z;i++)s+=Math.abs(b[i].c-b[i].o);return s/(z-a);};
        const ivmeSon=g(n-3,n), ivmeOnce=n>=6?g(n-6,n-3):ivmeSon;
        const ivme = ivmeSon>ivmeOnce*1.2 ? 'HIZLANIYOR' : ivmeSon<ivmeOnce*0.7 ? 'YAVAЕһLIYOR' : 'sabit';
        // SEBEPLER (saf kod tespiti)
        const sebepler = [];
        // 1) Hacim patlamasДұ
        const vSon=last.v, vOrt=(b[n-2].v+b[n-3].v+b[n-4].v)/3;
        if (vSon > vOrt*2) sebepler.push(`hacim ${(vSon/vOrt).toFixed(1)}x patladДұ`);
        // 2) Taker baskДұsДұ (alДұcДұ/satДұcДұ)
        let takerTxt = null;
        if (Array.isArray(agg) && agg.length) {
          const tr = Number(agg[agg.length-1]?.buySellRatio || 0);
          if (tr > 1.3) takerTxt = `agresif ALICI baskДұn (taker ${tr.toFixed(2)})`;
          else if (tr > 0 && tr < 0.77) takerTxt = `agresif SATICI baskДұn (taker ${tr.toFixed(2)})`;
        }
        if (takerTxt) sebepler.push(takerTxt);
        // 3) Mum karakteri (gГ¶vde/fitil)
        const govde = Math.abs(last.c-last.o), menzil = last.h-last.l||1e-9;
        const altFitil = Math.min(last.o,last.c)-last.l, ustFitil = last.h-Math.max(last.o,last.c);
        if (yon==='YГңKSELД°YOR' && govde/menzil > 0.6) sebepler.push('gГјГ§lГј yeЕҹil gГ¶vde (alДұm baskДұsДұ)');
        if (yon==='DГңЕһГңYOR' && govde/menzil > 0.6) sebepler.push('gГјГ§lГј kДұrmДұzДұ gГ¶vde (satДұЕҹ baskДұsДұ)');
        if (ustFitil/menzil > 0.5) sebepler.push('Гјst fitil uzun (yukarДұda satДұЕҹ/red)');
        if (altFitil/menzil > 0.5) sebepler.push('alt fitil uzun (aЕҹaДҹДұda alДұm/destek)');
        // 4) Д°vme durumu
        if (ivme==='HIZLANIYOR') sebepler.push(yon==='YГңKSELД°YOR'?'yГјkseliЕҹ ivmeleniyor (parabolik olabilir)':'dГјЕҹГјЕҹ ivmeleniyor (sert satДұЕҹ)');
        if (ivme==='YAVAЕһLIYOR') sebepler.push('momentum yavaЕҹlДұyor (hareket tГјkeniyor olabilir)');
        // 5) ArdДұЕҹДұk yГ¶n
        let ardisik=0; for(let i=n-1;i>=n-5;i--){ if(yon==='YГңKSELД°YOR'&&b[i].c>b[i].o)ardisik++; else if(yon==='DГңЕһГңYOR'&&b[i].c<b[i].o)ardisik++; else break; }
        if (ardisik>=3) sebepler.push(`${ardisik} ardДұЕҹДұk ${yon==='YГңKSELД°YOR'?'yeЕҹil':'kДұrmДұzДұ'} mum`);

        __r366VolSebep[base] = { ts:Date.now(), yon, hiz, ivme, sebepler: sebepler.slice(0,4) };
      } catch(_) {}
    }
    // Panele/AI'a aktar
    try { autoScanState.volatiliteSebep = __r366VolSebep; } catch(_) {}
  } catch(_) {}
}
setInterval(r366VolatiliteWorker, 30*1000); // 30sn'de bir вҖ” tarama arasДұ sГјrekli izleme (bedava, AI Г§aДҹДұrmaz)

