// R119: Auto panel tanДұ taЕҹДұyДұcДұlarДұ. R118 karar zinciri Г§alДұЕҹsa bile markAutoSkip
// eski R97 satДұrДұyla adayДұ gГјncellediДҹinde HTF/R115/R116/R117/R118 bilgileri panelden dГјЕҹГјyordu.
// Bu yardДұmcДұlar son kararДұn likidite haritasДұ + mum playbook bilgisini sembol bazДұnda korur.
const autoDiagBySymbol = new Map();
function r119FmtLevel(l) {
  try {
    if (!l) return '';
    const tf = String(l.label || l.tf || l.timeframe || '-');
    const px = Number(l.price || l.level || 0);
    const distRaw = l.dist ?? l.distancePct ?? l.distPct;
    const dist = Number.isFinite(Number(distRaw)) ? ` u:%${Number(distRaw).toFixed(2)}` : '';
    const strRaw = l.strength ?? l.guc ?? l.score;
    const str = Number.isFinite(Number(strRaw)) ? ` g:${Number(strRaw).toFixed(0)}` : '';
    return `${tf}${px ? ` ${px}` : ''}${dist}${str}`.trim();
  } catch { return ''; }
}
function r119BuildAutoDiag(dc={}) {
  try {
    const parts = [];
    if (dc.r110Phase) parts.push(`HTF faz:${dc.r110Phase}`);
    if (dc.r116HtfGuardBlock && !dc.r117HtfReverseOk) parts.push('HTF amir blok');
    if (dc.r117NearTrapHTF) parts.push(`ters-bГ¶lge ${r119FmtLevel(dc.r117TrapLevel)}`.trim());
    if (dc.r117HtfReverseOk) parts.push('ters-hedef HAZIR');
    if (dc.r118CandleOk) parts.push(`mum:${dc.r118CandleOzet||'OK'}`);
    else if (dc.r118CandleOzet) parts.push(`mum-izle:${dc.r118CandleOzet}`);
    if (dc.r111KoprusuOk) parts.push('sДұkДұЕҹma HAZIR');
    if (dc.r111SiksmaBreakout) parts.push(`patlama:${dc.r111SqueezeSkor||0}/4`);
    if (dc.r140Phase?.phase) parts.push(`R140 faz:${dc.r140Phase.phase}`);
    if (dc.r140OiVel?.fakePump) parts.push('R140 sahte-pump');
    if (dc.r140BtcDiv?.score) parts.push(`R140 BTC-div:+${dc.r140BtcDiv.score}`);

    const htf = [];
    if (dc.r110NearSSL) htf.push(`SSL ${r119FmtLevel(dc.r110NearSSL)}`);
    if (dc.r110NearBSL) htf.push(`BSL ${r119FmtLevel(dc.r110NearBSL)}`);
    if (dc.r116CounterLevel) htf.push(`KarЕҹДұ ${r119FmtLevel(dc.r116CounterLevel)}`);
    if (dc.r117TrapLevel) htf.push(`Ters ${r119FmtLevel(dc.r117TrapLevel)}`);

    const ictDashboard = String(dc.ictDashboard || dc.r88VurKac?.ictDashboard || htf.join(' | ') || '').slice(0,240);
    const siksmaOzet = String(dc.siksmaOzet || dc.r88VurKac?.siksmaOzet || dc.r111Siksma?.ozet || '').slice(0,220);
    const r119HtfDiag = parts.join(' В· ').slice(0,260);
    return {
      r111KoprusuOk: !!(dc.r111KoprusuOk || dc.r88VurKac?.r111KoprusuOk),
      siksmaOzet,
      ictDashboard,
      r119HtfDiag,
      r116HtfGuardBlock: !!dc.r116HtfGuardBlock,
      r116HtfGuardReason: String(dc.r116HtfGuardReason || '').slice(0,260),
      r117HtfReverseOk: !!dc.r117HtfReverseOk,
      r117HtfReverseReason: String(dc.r117HtfReverseReason || '').slice(0,260),
      r117NearTrapHTF: !!dc.r117NearTrapHTF,
      r117PrecisionCandleOk: !!dc.r117PrecisionCandleOk,
      r118CandleOk: !!dc.r118CandleOk,
      r118CandleStrong: !!dc.r118CandleStrong,
      r118CandleOzet: String(dc.r118CandleOzet || '').slice(0,220),
      r140Summary: String([
        dc.r140Phase?.phase ? `faz:${dc.r140Phase.phase}` : '',
        dc.r140OiVel?.summary ? dc.r140OiVel.summary : '',
        dc.r140BtcDiv?.label ? dc.r140BtcDiv.label : '',
        dc.r140EqHL?.summary ? dc.r140EqHL.summary : '',
        dc.r140Rvol?.signal ? `RVOL:${dc.r140Rvol.signal}Г—${dc.r140Rvol.rvol}` : ''
      ].filter(Boolean).join(' В· ')).slice(0,260)
    };
  } catch {
    return {};
  }
}

function pushAutoCandidate(row) {
  const symKey = String(row.symbol||'').replace('USDT','');
  const recKey = row.rec || 'WAIT';
  const prevDiag = autoDiagBySymbol.get(`${symKey}_${recKey}`) || autoDiagBySymbol.get(symKey) || {};
  const r = {
    ts:Date.now(),
    symbol:symKey,
    rec:recKey, recTR:trSideLabel(row.rec), tier:row.tier||'WAIT', tierTR:trTierLabel(row.tier||'WAIT'), score:Number(row.score||0),
    longScore:Number(row.longScore||0), shortScore:Number(row.shortScore||0),
    priorityScore:Number(row.priorityScore||0),
    reason:toTurkishText(String(row.reason||row.block||'вҖ”')).slice(0,220),
    reasonTR:toTurkishText(String(row.reason||row.block||'вҖ”')).slice(0,220),
    action:toTurkishText(String(row.action||'Д°zle')).slice(0,120),
    actionTR:toTurkishText(String(row.action||'Д°zle')).slice(0,120),
    sweepRequired: row.sweepRequired,
    entryPermissionReason: row.entryPermissionReason || '',
    entryPermissionReasonTR: toTurkishText(row.entryPermissionReason || ''),
    cvdMissing: !!row.cvdMissing,
    r45RvolStatus: row.r45RvolStatus || '',
    sikismaAktif: !!(row.r111KoprusuOk ?? row.sikismaAktif ?? prevDiag.sikismaAktif),
    siksmaOzet: String(row.siksmaOzet || prevDiag.siksmaOzet || '').slice(0,180),
    ictDashboard: String(row.ictDashboard || prevDiag.ictDashboard || '').slice(0,180),
    htfTani: String(row.r119HtfDiag || row.htfTani || prevDiag.htfTani || '').slice(0,260),
    htfBlok: !!((row.r117HtfReverseOk ? false : row.r116HtfGuardBlock) ?? row.htfBlok ?? prevDiag.htfBlok),
    htfBlokSebep: row.r117HtfReverseOk ? '' : String(row.r116HtfGuardReason || row.htfBlokSebep || prevDiag.htfBlokSebep || '').slice(0,260),
    tersHedef: !!(row.r117HtfReverseOk ?? row.tersHedef ?? prevDiag.tersHedef),
    tersHedefSebep: String(row.r117HtfReverseReason || row.tersHedefSebep || prevDiag.tersHedefSebep || '').slice(0,260),
    tersBolge: !!(row.r117NearTrapHTF ?? row.tersBolge ?? prevDiag.tersBolge),
    hassasMumOk: !!(row.r117PrecisionCandleOk ?? row.hassasMumOk ?? prevDiag.hassasMumOk),
    mumOnay: !!(row.r118CandleOk ?? row.mumOnay ?? prevDiag.mumOnay),
    mumGuclu: !!(row.r118CandleStrong ?? row.mumGuclu ?? prevDiag.mumGuclu),
    mumOzet: String(row.r118CandleOzet || row.mumOzet || prevDiag.mumOzet || '').slice(0,220),
    brainMode: row.brainMode || row.brain?.mode || '',
    brainAction: row.brainAction || row.brain?.action || (row.autoOk ? 'TRADE' : 'WAIT'),
    brainConfidence: Number(row.brainConfidence || row.brain?.confidence || 0),
    brainSummary: String(row.brainSummary || row.brain?.summary || '').slice(0,500),
    r125OrderflowSummary: String(row.r125OrderflowSummary || row.r125Flow?.summary || '').slice(0,300),
    r126FlowSummary: String(row.r126FlowSummary || row.r125Flow?.r126?.summary || '').slice(0,260),
    r140Summary: String(row.r140Summary || prevDiag.r140Summary || '').slice(0,260),
    r126PlaybookAdj: Number(row.r126PlaybookAdj || (row.brainMode ? r126PlaybookAdj(row.brainMode) : 0)),
    r125BestSide: row.r125BestSide || row.r125Flow?.bestSide || '',
    r125LiveDeltaPct: Number(row.r125LiveDeltaPct || row.r125Flow?.deltaPct || 0),
    autoOk: !!row.autoOk
  };
  const diagKeep = {
    sikismaAktif:r.sikismaAktif, siksmaOzet:r.siksmaOzet, ictDashboard:r.ictDashboard,
    htfTani:r.htfTani, htfBlok:r.htfBlok, htfBlokSebep:r.htfBlokSebep,
    tersHedef:r.tersHedef, tersHedefSebep:r.tersHedefSebep, tersBolge:r.tersBolge,
    hassasMumOk:r.hassasMumOk, mumOnay:r.mumOnay, mumGuclu:r.mumGuclu, mumOzet:r.mumOzet,
    r125OrderflowSummary:r.r125OrderflowSummary, r126FlowSummary:r.r126FlowSummary, r140Summary:r.r140Summary, r126PlaybookAdj:r.r126PlaybookAdj, r125BestSide:r.r125BestSide, r125LiveDeltaPct:r.r125LiveDeltaPct
  };
  autoDiagBySymbol.set(`${r.symbol}_${r.rec}`, diagKeep);
  autoDiagBySymbol.set(r.symbol, diagKeep);
  // R34: AynДұ sembol aynДұ taramada iki satДұr gГ¶rГјnmesin. Г–nce aday, sonra atlandДұ gelirse son durum yazДұlДұr.
  const key = `${r.symbol}_${r.rec}`;
  autoScanState.topCandidates = (autoScanState.topCandidates||[]).filter(x => `${x.symbol}_${x.rec}` !== key);
  autoScanState.topCandidates.push(r);
  const tierRank = t => t==='A'?3:t==='B+'?2:t==='B'?1:0;
  autoScanState.topCandidates = autoScanState.topCandidates
    .sort((a,b)=>tierRank(b.tier)-tierRank(a.tier) || b.score-a.score || (b.priorityScore||0)-(a.priorityScore||0) || b.ts-a.ts)
    .slice(0,12);
}
function markAutoSkip(symbol, reason, row={}) {
  const key = toTurkishText(String(reason||'Bilinmeyen')).slice(0,90);
  autoScanState.skipped = (autoScanState.skipped||0) + 1;
  autoScanState.skipReasons[key] = (autoScanState.skipReasons[key]||0) + 1;
  if (symbol) pushAutoCandidate({symbol, reason:key, action:'AtlandДұ', ...row});
}

// R308B: AI B-modu iГ§in analiz sДұrasДұnda dolan zengin context havuzu.
// AmaГ§: Eski kapДұlar adayДұ elese bile scan sonunda en iyi 1-2 adayДұ AI'ya gГ¶stermek.
const autoAiContextBySymbol = new Map();

function r308AiDayKey() { return new Date().toISOString().slice(0,10); }
function r308ReserveAiSpend(symbol, source='R308', fingerprint='') {
  const day = r308AiDayKey();
  if (r308AiSpendDay !== day) {
    r308AiSpendDay = day;
    r308AiSpendCount = 0;
    r308AiLastBySymbol.clear();
  }
  if (r308AiSpendCount >= AI_BRAIN_MAX_DAILY_CALLS) {
    return { ok:false, reason:`gГјnlГјk AI limit dolu ${r308AiSpendCount}/${AI_BRAIN_MAX_DAILY_CALLS}` };
  }
  const sym = String(symbol||'').replace('USDT','').toUpperCase();
  const now = Date.now();
  const prev = r308AiLastBySymbol.get(sym);
  // R311B: tekrar freni SADECE coin durumu AYNIYSA uygulanДұr. Durum deДҹiЕҹtiyse (yeni setup, farklДұ fingerprint)
  // AI'ya gitsin вҖ” EIGEN R285 q:99.8 gibi mГјkemmel YENД° setup'lar "tekrar freni" yГјzГјnden kaГ§masДұn. reviewGap'in
  // amacДұ aynДұ deДҹiЕҹmemiЕҹ duruma tekrar para harcamamak; yeni fДұrsatДұ engellemek DEДһД°L. fingerprint zaten setup'Дұn
  // Г¶zeti (yГ¶n+kademe+seviye). FarklДұysa = yeni durum = AI'ya deДҹer.
  const curFp = String(fingerprint||'').slice(0,120);
  const sameState = prev && curFp && String(prev.fingerprint||'') === curFp;
  if (prev && sameState && AI_BRAIN_REVIEW_GAP_MS > 0 && now - prev.ts < AI_BRAIN_REVIEW_GAP_MS) {
    return { ok:false, reason:`${sym} tekrar freni ${Math.ceil((AI_BRAIN_REVIEW_GAP_MS - (now-prev.ts))/1000)}sn (durum aynДұ)` };
  }
  r308AiSpendCount += 1;
  r308AiLastBySymbol.set(sym, { ts:now, source, fingerprint:curFp });
  return { ok:true, count:r308AiSpendCount };
}

function r308RememberAiContext(symbol, coin, analysis, decisionChain, recommendation, score, skipReason='') {
  try {
    const sym = String(symbol || coin?.symbol || coin?.fullSymbol || '').replace('USDT','').toUpperCase();
    if (!sym || !analysis) return;
    const r300Rsi5m = Number(analysis?.timeframes?.['5m']?.rsi);
    const r300Rsi4h = Number(analysis?.timeframes?.['4h']?.rsi);
    const rangePos = Number.isFinite(decisionChain?._r276RangePos) ? decisionChain._r276RangePos
      : (decisionChain?.r281ProMap && Number.isFinite(decisionChain.r281ProMap.rangePos) ? decisionChain.r281ProMap.rangePos : 0.5);
    autoAiContextBySymbol.set(sym, {
      aiSource: 'R308D_TOP1_SCAN',
      recommendation, score, skipReason,
      lastPrice: Number(coin?.lastPrice || analysis?.price || analysis?.lastPrice || analysis?.ticker?.lastPrice || 0),
      rsi5m: Number.isFinite(r300Rsi5m) ? r300Rsi5m : undefined,
      rsi15m: analysis?.timeframes?.['15m']?.rsi,
      rsi1h: analysis?.timeframes?.['1h']?.rsi,
      rsi4h: Number.isFinite(r300Rsi4h) ? r300Rsi4h : analysis?.timeframes?.['4h']?.rsi,
      trend5m: analysis?.timeframes?.['5m']?.trend, trend15m: analysis?.timeframes?.['15m']?.trend,
      trend1h: analysis?.timeframes?.['1h']?.trend, trend4h: analysis?.timeframes?.['4h']?.trend,
      structure: decisionChain?.htfTani || decisionChain?.mumOzet || decisionChain?.r119HtfDiag || '',
      liquidity: decisionChain?.ictDashboard || '',
      fvg: decisionChain?.r274Signal?.summary || analysis?.fvg || '',
      ote: decisionChain?.r110ICT?.summary || '',
      sweepInfo: decisionChain?.r289Summary || String(decisionChain?.brainSummary||decisionChain?.reason||'').slice(0,260),
      flow: decisionChain?.r125OrderflowSummary || '',
      funding: analysis?.funding?.current,
      oiChange: decisionChain?.r140Summary || '',
      squeeze: (decisionChain?.r111Sonuc?.shortSqueeze ? 'shortSqueeze' : decisionChain?.r111Sonuc?.longSqueeze ? 'longSqueeze' : 'yok'),
      atrPct: analysis?.leverage?.atrPct || decisionChain?.coinAtrPct,
      rangePos,
      candleSummary: decisionChain?.mumOzet || decisionChain?.r118CandleOzet || '',
      // R311X: KABA fingerprint вҖ” mikro oynamalar (skor 67вҶ’68, reason'da sayДұ deДҹiЕҹimi) "yeni durum" sayДұlДұp
      // AI'ya boЕҹa tekrar sordurmasДұn. Sadece GERГҮEK deДҹiЕҹiklik yeni Г§aДҹrДұ tetikler: yГ¶n / skor-dilimi(10luk) /
      // sweep var-yok / tier. Sweep geldiДҹinde ya da yГ¶n dГ¶ndГјДҹГјnde fingerprint zaten deДҹiЕҹir вҶ’ fДұrsat kaГ§maz.
      fingerprint: [
        recommendation,
        Math.floor(Number(score||0)/10)*10,                                  // 67 ve 68 вҶ’ ikisi de 60 dilimi
        (/sweep|sГјpГјr|reclaim|geri kazan|вң…/i.test(String(decisionChain?.r289Summary||decisionChain?.ictDashboard||decisionChain?.reason||'')) ? 'SW1' : 'SW0'), // sweep durumu deДҹiЕҹti mi
        String(decisionChain?.tier||decisionChain?.tierTR||'').slice(0,3)
      ].join('|')
    });
  } catch(_) {}
}

function r308BuildAiDataFromCandidate(c) {
  const sym = String(c?.symbol||'').replace('USDT','').toUpperCase();
  const ctx = autoAiContextBySymbol.get(sym) || {};
  return {
    ...ctx,
    aiSource: 'R308D_TOP1_SCAN',
    recommendation: c?.rec || ctx.recommendation || null,
    score: Number(c?.score || ctx.score || 0),
    skipReason: c?.reason || ctx.skipReason || '',
    structure: ctx.structure || c?.htfTani || c?.mumOzet || '',
    liquidity: ctx.liquidity || c?.ictDashboard || '',
    flow: ctx.flow || c?.r125OrderflowSummary || c?.r126FlowSummary || '',
    oiChange: ctx.oiChange || c?.r140Summary || '',
    candleSummary: ctx.candleSummary || c?.mumOzet || '',
    fingerprint: ctx.fingerprint || [c?.rec, Math.floor(Number(c?.score||0)/10)*10, (/sweep|sГјpГјr|reclaim|geri kazan|вң…/i.test(String(c?.reason||'')) ? 'SW1':'SW0'), String(c?.tier||'').slice(0,3)].join('|')
  };
}

function r308AiPlanQuality(ai) {
  try {
    const side = String(ai?.side || '').toUpperCase();
    const entry = Number(ai?.entry);
    const tp = Number(ai?.tp);
    const sl = Number(ai?.sl);
    const conf = Number(ai?.confidence || 0);
    // R308Y: GГңVEN TABANI 64. AI 64 altДұ gГјvenle aГ§amaz (zayДұf iЕҹlem = kayДұp kaynaДҹДұ). 64+ ise karar AI'ya bДұrakДұlДұr.
    // Sadece plan GEГҮERLД°LД°ДһД° + aЕҹДұrДұ-geniЕҹ-SL gГјvenliДҹi + gГјven tabanДұ kontrol edilir.
    if (!['LONG','SHORT'].includes(side)) return { ok:false, reason:`AI ${side || 'WAIT'} dedi` };
    if (conf < AI_BRAIN_CONF_FLOOR) return { ok:false, reason:`AI gГјven ${conf}% < ${AI_BRAIN_CONF_FLOOR} taban вҖ” zayДұf iЕҹlem aГ§ДұlmadДұ (AI yeterince emin deДҹil)` };
    if (![entry,tp,sl].every(x => Number.isFinite(x) && x > 0)) return { ok:false, reason:'AI giriЕҹ/TP/SL sayДұsal deДҹil' };
    const isLong = side === 'LONG';
    if (isLong && !(tp > entry && sl < entry)) return { ok:false, reason:'AI LONG TP/SL yГ¶nГј hatalДұ' };
    if (!isLong && !(tp < entry && sl > entry)) return { ok:false, reason:'AI SHORT TP/SL yГ¶nГј hatalДұ' };
    const risk = Math.abs(entry - sl);
    const reward = Math.abs(tp - entry);
    if (!(risk > 0 && reward > 0)) return { ok:false, reason:'AI risk/Г¶dГјl sДұfДұr' };
    const rr = reward / risk;
    const slPct = risk / entry * 100;
    // R334: SL LД°MД°TД° KALDIRILDI (kullanДұcДұ kararДұ) вҖ” AI ne derse o. Volatil gainer coinlerde sweep dibi doДҹal olarak
    // geniЕҹ SL gerektirir (%9 gibi); dar limit iyi iЕҹlemleri reddediyordu (TLM tipi kaГ§an iЕҹlemler). AI kendi SL'ini seГ§er.
    // GГңVENLД°K: geniЕҹ SL'de likidasyon riskini kaldДұraГ§ dengeler вҖ” executeLeverage SL%'ye gГ¶re otomatik dГјЕҹГјrГјlГјr (aЕҹaДҹДұda).
    // (Eski %3/%6 red kaldДұrДұldДұ; AI'Дұn yargДұsДұ esas.)
    if (!(slPct > 0)) return { ok:false, reason:'AI SL geГ§ersiz (0 ya da negatif)' };
    // NOT (R310O): R310N min R/R zorlamasДұ KALDIRILDI вҖ” AI bazen dГјЕҹГјk R/R'lДұ ama yГјksek-olasДұlДұklДұ scalp
    // setup gГ¶rГјr (yakДұn TP, kesin kГўr). KatДұ R/R dayatmak AI'nДұn yargДұsДұnДұ ezer = boДҹma. R/R bilgi olarak
    // hesaplanДұp gГ¶sterilir; AI kendi deДҹerlendirir. Sadece SL aЕҹДұrДұ geniЕҹliДҹi (gГјvenlik) ve gГјven tabanДұ kalДұr.
    return { ok:true, rr, slPct, confidence:conf };
  } catch(e) {
    return { ok:false, reason:String(e?.message || e).slice(0,120) };
  }
}

