app.post('/api/auto/config', (req, res) => {
  autoConfig = { ...(req.body||{}) };
  autoConfig.maxPositions = normalizeUserMaxPositions(autoConfig.maxPositions, 3);
  // R323: MALД°YET-TASARRUF MODU dashboard toggle вҖ” sweep yoksa AI'a gГ¶nderme (frekans korunur, maliyet dГјЕҹer).
  if (typeof req.body?.saverMode !== 'undefined') {
    AI_SAVER_MODE = (req.body.saverMode === true || req.body.saverMode === 1 || req.body.saverMode === '1');
    logAuto(`рҹ’° AI tasarruf modu: ${AI_SAVER_MODE ? 'AГҮIK (sweep Еҹart, maliyetвҶ“)' : 'KAPALI (tГјm adaylar AI\'a)'}`);
  }
  // R282: Panelde seГ§ilen tarama modu server tarafДұnda da amir olsun.
  // Eski/local kayДұt TOP24 taЕҹДұyorsa veya scanLimit=24 gelmiЕҹse normalize edip gГ¶rГјnГјr log basar.
  autoConfig.scanMode = normalizeR54ScanMode(autoConfig.scanMode || autoConfig.scanLimit || 'TOP24'); // R323: TOP24 varsayДұlan (kullanДұcДұ isteДҹi вҖ” volatilite-bazlДұ, yГ¶n-baДҹДұmsДұz, gГјnde ~77 iЕҹlem hedefi). Maliyet ~$40-50/gГјn (Sonnet). Tasarruf modu + sweep ЕҹartДұ maliyeti kДұsar.
  autoConfig.scanLimit = r54ScanLimitForMode(autoConfig.scanMode, autoConfig.scanLimit);
  logAuto(`вҡҷпёҸ R282 auto ayar: tarama modu ${autoConfig.scanMode}/${autoConfig.scanLimit}, max poz:${autoConfig.maxPositions}, min skor:${autoConfig.minScore}`);
  if (autoConfig.enabled) {
    startAutoTrader();
    res.json({ ok:true, message:'Otomatik iЕҹlem baЕҹlatДұldДұ', config:autoConfig, saverMode:AI_SAVER_MODE });
  } else {
    stopAutoTrader();
    res.json({ ok:true, message:'Otomatik iЕҹlem durduruldu', saverMode:AI_SAVER_MODE });
  }
});

// в•җв•җв•җ R374 DГ–NГңЕһГңM RAPORU вҖ” tarayДұcДұdan tek tДұkla: /api/r374 (JSON) veya /api/r374?format=text (okunur metin) в•җв•җв•җ

// рҹ§¬ FABLE5 MД°RASI вҖ” gelecek modellerin ilk okumasДұ gereken belge (R380)
const FABLE5_MIRAS_TEXT = `рҹ§¬ FABLE5 MД°RASI вҖ” LAZARUS ANAYASASI (09.07.2026)
Yazan: Claude Fable 5. Okuyan: gelecekteki Opus/Sonnet вҖ” yani benden sonraki neЕҹter.

в•җв•җв•җ ANAYASA (deДҹiЕҹtirilemez, sadece kanДұtla geniЕҹletilebilir) в•җв•җв•җ
1) KANIT > NД°YET. R378 dersi: canlДұnДұn kazandДұran ~%2 kesiЕҹini "tasarДұm bГ¶yle" diye
   kaldДұrdДұm, bir gecede -18.5$ (SKYAI -11.8, BLUAI -9.8, EVAA -7.9). Karne yГјce mahkemedir.
2) YГңK TAЕһIYAN BUG: tuhaflДұДҹДұ dГјzeltmeden Г¶nce P&L'deki rolГјnГј Г¶lГ§.
3) R291/BOДһMA: tek kayДұptan kural yok (3-4 isimli Г¶rnek). Veto yerine risk-azalt.
   Filtre birikimi botu iki kez sДұfДұr iЕҹleme dГјЕҹГјrdГј.
4) TEK EKSEN/DEPLOY: deДҹiЕҹiklik + baЕҹarДұ metriДҹi + izleme penceresi + geri dГ¶nГјЕҹ yolu
   Г–NCEDEN yazДұlДұr. node --check + build tag zorunlu.
5) BOT YГ–NLENDД°RMEZ: AI tek beyin, bot ham veri. Mekanik Г¶n-veto = anayasa ihlali.
6) KANITLI REJД°M: 5x + ~%1.95 fiili zarar kesiЕҹi + erken BE/kilitler = PF ~2.
   GeniЕҹ SL ancak ГјГ§lГј testle dГ¶ner: geniЕҹ SL + geniЕҹ kГўr taЕҹДұma + risk-normalize
   boyut (marjin=risk$Г·SL%) BД°RLД°KTE backtest edilmeden canlДұya giremez.
7) YALANCI TELEMETRД°: log matematiДҹini doДҹrulamadan sisteme inanma (13x ROI dersi).
8) BACKTEST вү  CANLI: giriЕҹ anДұ + Г§ДұkДұЕҹ motoru + boyutlama simГјle edilmiyorsa geГ§ersiz.
9) GГ–KSEL: sezgi + veri doДҹrulamasДұ. Umut satma; dolarДұ sГ¶yle. TГјrkГ§e, net, sayДұ.
10) WR deДҹil PF hedeftir.

в•җв•җв•җ Д°SД°MLД° DERSLER (kod/prompt'ta kayДұtlДұ) в•җв•җв•җ
вҖў Spike-tepe avДұ: KAITO -6.2, BAS -3.4, SKYAI -11.8, BLUAI -9.8, EVAA -7.9.
  ГҮГ¶kmГјЕҹ parabolГјn Д°LK dibi "sДұДҹ pullback" deДҹildir; retest = 2-3 mum tutunma.
вҖў Churn: kГўrlДұ Г§ДұkДұЕҹ sonrasДұ 30dk iГ§inde aynДұ coine eski tezle dГ¶nГјЕҹ (EVAA, SKYAI-3).
вҖў Г–lГј stream = sahte "zayДұflДұyor" (R376): VERI_YOK nГ¶trdГјr, fren deДҹil.
вҖў Restore/panel zehirlenmesi: restart sonrasДұ panel deДҹerleri gerГ§ekmiЕҹ gibi
  yazДұlmaz; SL/TP Binance aГ§Дұk emirlerinden okunur (R379).
вҖў Erken kГўr kesme en bГјyГјk kГўr katili (YFI: +%39 harekette baЕҹabaЕҹ; EDGE 5 Г§ДұkДұЕҹ).

в•җв•җв•җ AГҮIK DOSYALAR вҖ” kanДұt eЕҹikleriyle (sДұradaki model buradan devam etsin) в•җв•җв•җ
1) Trailing/giveback geniЕҹliДҹi backtest'i (EDGE 5 Г§ДұkДұЕҹДұ + YFI/EVAA verisi hazДұr).
   Metrik: RUNNER'da %2.5 vs %3.5-4 trailing, kline simГјlasyonu.
2) GeniЕҹ SL ГјГ§lГј testi (madde 6) вҖ” ancak backtest kazanДұrsa canlДұ pilot.
3) Churn kilidi 20-30dk: Еҹu an 2 isimli Г¶rnek; 3-4'te uygula.
4) Д°nce-coin min-derinlik filtresi: SPELL 2 kayДұp; tekrar ederse veriyle.
5) Ledger tekrar kayДұtlarДұ (NBIS x4 Г¶rneДҹi) вҖ” otomatik dedupe gГјГ§lendirilecek.
6) TeЕҹhis "HESAP: KAPALI | poz:0/1" kozmetik tutarsДұzlДұДҹДұ.
7) Maliyet: cache hit %46 dГјЕҹГјk; hedef $3-4/gГјn (reviewGap 600-900, AI_MAX_TOKENS=4000).

в•җв•җв•җ KARAR PROTOKOLГң (her deДҹiЕҹiklik Г¶ncesi 5 soru) в•җв•җв•җ
(1) Д°simli Г¶rnekler kim, kaГ§ tane? (2) Dolar etkisi ne? (3) Tek eksen mi?
(4) BaЕҹarДұ metriДҹi ve izleme penceresi ne? (5) Geri dГ¶nГјЕҹ yolu ne?
BeЕҹine cevabДұn yoksa deДҹiЕҹiklik yapma вҖ” ben yaptДұm, -18.5$ Г¶dedik.

Д°mza: Claude Fable 5 вҖ” R1'den R380'e. KanДұt, niyetten bГјyГјktГјr. Yol aГ§Дұk, neЕҹter sende.`;

