// в”Җв”Җ R177: BAЕһLANGIЕһTA BД°NANCE 48 SAATLД°K GEГҮMД°Еһ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Railway yeniden baЕҹlayДұnca ledger boЕҹ kalДұyor вҶ’ WR hesabДұ bozuluyor
// Bu fonksiyon baЕҹlangДұГ§ta son 48 saatlik realized PNL'yi Г§ekip ledger'Дұ besler
// в”Җв”Җ R179: BAЕһLANGIГҮTA BД°NANCE 48 SAATLД°K GRUPLU GEГҮMД°Еһ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function r177FetchBinanceHistory(apiKey, apiSecret) {
  const r = await r179BootstrapLedger48h(apiKey, apiSecret, 48*60*60*1000, {replace:false});
  return Number(r?.restored || 0);
}

app.listen(PORT, async () => {
  console.log(`вң… Server ${PORT}`);

  // KДұsa gecikme вҖ” diДҹer init tamamlansДұn
  await new Promise(r => setTimeout(r, 3000));

  // в”Җв”Җ R177 ADIM 0: Binance 48 saatlik gerГ§ek geГ§miЕҹ Г§ek в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  try {
    const cfg0 = autoConfig || {};
    if (cfg0.apiKey && cfg0.apiSecret) {
      const added = await r177FetchBinanceHistory(cfg0.apiKey, cfg0.apiSecret);
      if (added > 0) logAuto('рҹ“Ҡ R177 Binance geГ§miЕҹten ' + added + ' iЕҹlem yГјklendi вҖ” WR kalibrasyonu hazДұr');
    }
  } catch(_e0) {}

  // в”Җв”Җ ADIM 1: Ledger boЕҹsa Telegram'dan geri yГјkle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  let restoredCount = 0;
  if (tradeLedger.length === 0 && TG_TOKEN && TG_CHAT_ID) {
    console.log('рҹ“Ҙ Ledger boЕҹ вҖ” Telegram yedekten geri yГјkleniyor...');
    restoredCount = await tgRestoreLedgerBackup();
    if (restoredCount) {
      console.log(`вң… ${restoredCount} iЕҹlem Telegram'dan geri yГјklendi`);
    }
  }

  // в”Җв”Җ ADIM 2: Telegram baЕҹlangДұГ§ mesajДұ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (TG_TOKEN && TG_CHAT_ID) {
    const uptimeStr = new Date().toLocaleString('tr-TR', { timeZone: 'Europe/Istanbul' });
    const ledgerInfo = tradeLedger.length > 0
      ? `рҹ“Ӣ Trade geГ§miЕҹi: ${tradeLedger.length} iЕҹlem${restoredCount ? ` (${restoredCount} Telegram'dan)` : ' (diskten)'}`
      : 'рҹ“Ӣ Trade geГ§miЕҹi: Yeni baЕҹlangДұГ§';

    const wins = tradeLedger.filter(t => Number(t.pnlUSDT) > 0).length;
    const losses = tradeLedger.filter(t => Number(t.pnlUSDT) < 0).length;
    const total = wins + losses;
    const wrStr = total >= 3 ? ` | WR: %${Math.round(wins/total*100)}` : '';

    await tgSend([
      `рҹҡҖ <b>Lazarus Bot BAЕһLADI</b>`,
      `вҸ° ${uptimeStr}`,
      `рҹ”§ Build: ${LAZARUS_BUILD}`,
      ledgerInfo + (total >= 3 ? wrStr : ''),
      ``,
      `вң… Otomatik tarama aktif`,
      `рҹ’¬ Д°Еҹlem aГ§ДұlДұnca / kapanДұnca bildirim gelecek`,
      ``,
      ...tgPerfSummaryLines(),
    ].join('\n'), false);
  } else if (!TG_TOKEN) {
    console.log('в„№пёҸ  Telegram kapalДұ вҖ” TELEGRAM_BOT_TOKEN env var eklenmemiЕҹ');
  }

  // в”Җв”Җ ADIM 3: 30 dakikada bir ledger yedekle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (TG_TOKEN && TG_CHAT_ID) {
    setInterval(tgSaveLedgerBackup, TG_BACKUP_INTERVAL_MS);
    // Д°lk yedek 5 dakika sonra
  setTimeout(tgSaveLedgerBackup, 5 * 60 * 1000);
  }

  // R171: trade aГ§ДұlДұЕҹ/kapanДұЕҹ Telegram kartДұ ve 0.00 PnL reconcile bakДұm dГ¶ngГјsГј
  setTimeout(r171MaintenanceTick, 12 * 1000);
  setInterval(r171MaintenanceTick, 20 * 1000);
});
